SELECT count(*) FROM movie_keyword, title, movie_info, keyword, info_type, kind_type, movie_companies, cast_info, company_name WHERE movie_keyword.movie_id = title.id AND movie_info.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND movie_info.info_type_id = info_type.id AND title.kind_id = kind_type.id AND movie_companies.movie_id = title.id AND cast_info.movie_id = title.id AND movie_companies.company_id = company_name.id;